<template>
  <div class="sign">
    <transition name="fade">
      <Message v-if="messagePopup" @closeMessagePopup="closeMessagePopup" :title="message.title"
               :description="message.description"/>
    </transition>
    <div class="container sign__content">
      <h2 class="sign__title">Вход</h2>
      <form @submit.prevent="signIn" class="sign__form">
        <input type="text" placeholder="Login" v-model="form.login">
        <input type="password" placeholder="Password" v-model="form.password">
        <button type="submit">Войти</button>
        <router-link to="/sign-up" class="sign__reg" tag="div">Зарегистрироваться</router-link>
      </form>

    </div>
    <Nav/>
  </div>
</template>

<script>
import Nav from "@/components/Nav.vue";
import Message from "@/components/Message.vue";

export default {
  components: {
    Nav,
    Message,
  },
  data() {
    return {
      form: {
        login: '',
        password: '',
      },
      messagePopup: false,
      message: {
        title: 'Ошибка',
        description: 'Ошибка валидации',
      }
    }
  },
  computed: {
    apiUrl() {
      return this.$store.getters.apiUrl;
    },
    token() {
      return this.$store.getters.token;
    }
  },
  mounted() {
    if (this.token.length) {
      this.$router.push('/profile')
    }
  },
  methods: {
    async signIn() {
      if (this.form.login && this.form.password) {
        const response = await fetch(`${this.apiUrl}/api/account/login`, {
          method: "POST",
          headers: {
            'Content-Type': 'application/json'
          },
          body: JSON.stringify({
            username: this.form.login,
            password: this.form.password,
          }),
        })
        const status = await response.json();
        if (response.ok) {
          console.log(status.token);
          if (status.token) {
            this.$store.commit('signIn', status.token);
            localStorage.token = status.token;
            this.$router.push('/profile');
          } else {
            this.messagePopup = true;
            this.message.description = 'Непредвиденная ошибка, обратитесь к разработчикам данного продукта'
          }
        } else {
          console.log(status)
          this.messagePopup = true

          if (status.message) {
            this.message.description = status.message;
          }
        }
      } else {
        this.messagePopup = true
        this.message.description = 'Логин и пароль обязательны';
      }

    },
    closeMessagePopup() {
      this.messagePopup = false;
    }
  }
}
</script>
